import { MovieProfile } from '../movie-profile';
import axios from 'axios';
import { useEffect, useState } from 'react';
import { LoadingPage } from '../loading-page';
import { Link } from 'react-router-dom';
import { formatLanguageToApi } from '../utils/api-utils';
import { LoadMoreButton } from '../load-more/load-more-button';
import { LANGUAGES } from '../../i18n/translations';
import MoviesGrid from './movies-grid';
import StartModal from '../start-modal';
import { useUserPreferences } from '../../context/userPreferences';

export function HomePage() {
	const [topMovies, setTopMovies] = useState<MoviesInformation>({ results: [], type: '' });
	const [isLoading, setIsLoading] = useState(false);
	const [topMoviesGridVisibility, setTopMoviesGridVisibility] = useState(false);

	const { language, theme } = useUserPreferences();

	const token = `Bearer ${process.env.REACT_APP_TMDB_BEARER_TOKEN}`;
	const genresUrl = 'https://api.themoviedb.org/3/genre/movie/list?api_key=8a9b6d3eb71a15a13f2cbef497bb7474';
	const topMoviesUrl = 'https://api.themoviedb.org/3/movie/top_rated?api_key=8a9b6d3eb71a15a13f2cbef497bb7474&language=pt-BR';

	async function getTopMovieData() {
		setIsLoading(true);
		const topMoviesResponse = await axios({
			method: 'get',
			url: topMoviesUrl,
			headers: { Authorization: token }
		});
		setTopMovies({ ...topMoviesResponse.data, type: 'topMovies' });

		setIsLoading(false);
	}

	function renderGrid(index: number, movie: any, gridVisibility: boolean) {
		switch (true) {
		case index < 4:
		case index >= 4 && gridVisibility === true:
			return (
				<Link to={`/movie/${movie.id}`} key={movie.id} accessKey="abc">
					<MovieProfile pictureUrl={`https://image.tmdb.org/t/p/w500${movie.poster_path}`} title={movie.title} releaseDate={movie.release_date} />
				</Link>
			);
		}
	}

	useEffect(() => {
		getTopMovieData();
	}, [language]);

	return (
		<div className={`${theme.themeBgClassName} ${theme.themeTextClassName} h-100`}>
			{isLoading ? (
				<LoadingPage />
			) : (
				<>
					<div className="bg-[url('/Users/denzelwallace/Desktop/Me/Estudos/React/dmdb-app/public/assets/background.jpg')] bg-cover backdrop-blur-3xl bg-center text-center p-72">
						<p className="text-9xl font-extrabold text-white">DMDB</p>
						<p className="text-2xl text-white"> {LANGUAGES[language].homePageSubtitle}</p>
					</div>
					<div>
						<StartModal/>
						<MoviesGrid genre={10749}/>
						<MoviesGrid genre={16}/>
					</div>
				</>
			)}
		</div>
	);
}
